package com.wjx871.population.certificate;import com.wjx871.population.security.SensitiveDataMaskingService;import java.time.*;
public record CertificateView(Long certificateId,Long personId,String personName,String personIdCard,String personPhone,String personAddress,String certificateType,String certificateNo,LocalDate issueDate,LocalDate expireDate,String status,String cancelReason,LocalDateTime cancelledAt,Integer version,LocalDateTime createdAt,LocalDateTime updatedAt){static CertificateView from(Certificate c,SensitiveDataMaskingService m){String s="ACTIVE".equals(c.getStatus())&&c.getExpireDate()!=null&&c.getExpireDate().isBefore(LocalDate.now())?"EXPIRED":c.getStatus();return new CertificateView(c.getCertificateId(),c.getPersonId(),c.getPersonName(),m.identity(c.getPersonIdCard()),m.phone(c.getPersonPhone()),m.address(c.getPersonAddress()),c.getCertificateType(),m.permit(c.getCertificateNo()),c.getIssueDate(),c.getExpireDate(),s,c.getCancelReason(),c.getCancelledAt(),c.getVersion(),c.getCreatedAt(),c.getUpdatedAt());}}
